using System.Net.Http.Json;
using System.Text.Json.Serialization;

namespace McpServer;

/// <summary>Typed HttpClient wrapper for the Open-Meteo API.</summary>
public sealed class WeatherApiClient(HttpClient http)
{
    public async Task<WeatherResponse?> GetCurrentWeatherAsync(
        double latitude, double longitude, CancellationToken ct = default)
    {
        var url = $"v1/forecast?latitude={latitude}&longitude={longitude}"
                + "&current=temperature_2m,wind_speed_10m";

        return await http.GetFromJsonAsync<WeatherResponse>(url, ct);
    }
}

public sealed class WeatherResponse
{
    [JsonPropertyName("current")]
    public CurrentWeather? Current { get; set; }
}

public sealed class CurrentWeather
{
    [JsonPropertyName("temperature_2m")]
    public double Temperature { get; set; }

    [JsonPropertyName("wind_speed_10m")]
    public double WindSpeed { get; set; }
}

using System.ComponentModel;
using ModelContextProtocol.Server;

namespace McpServer;

[McpServerToolType]
public sealed class WeatherTools(WeatherApiClient api)
{
    [McpServerTool, Description("Get current weather for a location.")]
    public async Task<string> GetCurrentWeather(
        [Description("Latitude of the location")]  double latitude,
        [Description("Longitude of the location")] double longitude,
        CancellationToken ct = default)
    {
        var result = await api.GetCurrentWeatherAsync(latitude, longitude, ct);

        if (result?.Current is null)
            return "Weather data unavailable.";

        return $"Temperature: {result.Current.Temperature}°C, "
             + $"Wind: {result.Current.WindSpeed} km/h";
    }
}

